import { describe, expect, it } from '@a0n/gnosis/test';
import { createReactorHandleGrant } from './auth/reactor-attestation';
import {
  deriveExecutionAuthFromHeaders,
  generateNativeExecutionReactorGrantSigner,
  summarizeNativeExecutionAuth,
} from './native-execution-auth';

describe('native-execution-auth', () => {
  it('derives request-scoped reactor handle grants from forwarded headers', async () => {
    const signer = await generateNativeExecutionReactorGrantSigner(
      'native-auth-test'
    );
    const now = Date.now();
    const claimsBase = {
      ownerDid: 'did:key:alice',
      audience: 'aeon://gnosis/native-execution',
      ucanCapabilities: ['gnosis/steering.run *', 'aeon/process *'],
      runtimeBindingHash:
        'binding-native-runtime-0123456789abcdef0123456789abcdef',
      issuedAt: now,
      expiresAt: now + 60_000,
    } as const;
    const requestGrant = await createReactorHandleGrant({
      claims: {
        ...claimsBase,
        handleId: 'request:test-1',
        kind: 'request',
        resource: 'POST /.aeon/gnode/execute',
        operations: ['request.metadata', 'request.read'],
      },
      privateKey: signer.privateKey,
      keyId: signer.keyId,
      publicKey: signer.publicKey,
    });
    const responseGrant = await createReactorHandleGrant({
      claims: {
        ...claimsBase,
        handleId: 'response:test-1',
        kind: 'response',
        resource: 'POST /.aeon/gnode/execute#response',
        operations: ['response.start', 'response.write', 'response.end'],
      },
      privateKey: signer.privateKey,
      keyId: signer.keyId,
      publicKey: signer.publicKey,
    });

    const auth = await deriveExecutionAuthFromHeaders({
      'x-aeon-auth-verified': '1',
      'x-aeon-actor': 'did:key:alice',
      'x-ucan-capabilities': 'gnosis/steering.run,aeon/process',
      'x-aeon-runtime-binding-hash':
        'binding-native-runtime-0123456789abcdef0123456789abcdef',
      'x-aeon-reactor-handle-grants': JSON.stringify([
        requestGrant,
        responseGrant,
      ]),
    });
    const summary = summarizeNativeExecutionAuth(auth, 'headers');

    expect(auth?.principal).toBe('did:key:alice');
    expect(auth?.reactorHandleGrants?.length).toBe(2);
    expect(
      auth?.reactorHandleGrants?.map((grant) => grant.claims.kind)
    ).toEqual(['request', 'response']);
    expect(summary?.reactorHandleGrantCount).toBe(2);
    expect(summary?.reactorHandleKinds).toEqual(['request', 'response']);
  });

  it('drops forwarded reactor handle grants when the runtime binding hash drifts', async () => {
    const signer = await generateNativeExecutionReactorGrantSigner(
      'native-auth-drift-test'
    );
    const now = Date.now();
    const requestGrant = await createReactorHandleGrant({
      claims: {
        handleId: 'request:test-drift',
        kind: 'request',
        ownerDid: 'did:key:alice',
        audience: 'aeon://gnosis/native-execution',
        resource: 'POST /.aeon/gnode/execute',
        operations: ['request.metadata', 'request.read'],
        ucanCapabilities: ['gnosis/steering.run *'],
        runtimeBindingHash:
          'binding-native-runtime-0123456789abcdef0123456789abcdef',
        issuedAt: now,
        expiresAt: now + 60_000,
      },
      privateKey: signer.privateKey,
      keyId: signer.keyId,
      publicKey: signer.publicKey,
    });

    const auth = await deriveExecutionAuthFromHeaders({
      'x-aeon-auth-verified': '1',
      'x-aeon-actor': 'did:key:alice',
      'x-aeon-runtime-binding-hash':
        'binding-native-runtime-mismatch-ffffffffffffffffffffffffffff',
      'x-aeon-reactor-handle-grants': JSON.stringify([requestGrant]),
    });

    expect(auth?.principal).toBe('did:key:alice');
    expect(auth?.reactorHandleGrants?.length ?? 0).toBe(0);
  });

  it('drops forwarded reactor handle grants when the signature is tampered', async () => {
    const signer = await generateNativeExecutionReactorGrantSigner(
      'native-auth-tamper-test'
    );
    const now = Date.now();
    const requestGrant = await createReactorHandleGrant({
      claims: {
        handleId: 'request:test-tamper',
        kind: 'request',
        ownerDid: 'did:key:alice',
        audience: 'aeon://gnosis/native-execution',
        resource: 'POST /.aeon/gnode/execute',
        operations: ['request.metadata', 'request.read'],
        ucanCapabilities: ['gnosis/steering.run *'],
        runtimeBindingHash:
          'binding-native-runtime-0123456789abcdef0123456789abcdef',
        issuedAt: now,
        expiresAt: now + 60_000,
      },
      privateKey: signer.privateKey,
      keyId: signer.keyId,
      publicKey: signer.publicKey,
    });

    const tamperedGrant = {
      ...requestGrant,
      claims: {
        ...requestGrant.claims,
        resource: 'POST /.aeon/gnode/execute-tampered',
      },
    };

    const auth = await deriveExecutionAuthFromHeaders({
      'x-aeon-auth-verified': '1',
      'x-aeon-actor': 'did:key:alice',
      'x-aeon-runtime-binding-hash':
        'binding-native-runtime-0123456789abcdef0123456789abcdef',
      'x-aeon-reactor-handle-grants': JSON.stringify([tamperedGrant]),
    });

    expect(auth?.reactorHandleGrants?.length ?? 0).toBe(0);
  });

  it('drops replayed forwarded reactor handle grants on the second use', async () => {
    const signer = await generateNativeExecutionReactorGrantSigner(
      'native-auth-replay-test'
    );
    const now = Date.now();
    const requestGrant = await createReactorHandleGrant({
      claims: {
        handleId: 'request:test-replay',
        kind: 'request',
        ownerDid: 'did:key:alice',
        audience: 'aeon://gnosis/native-execution',
        resource: 'POST /.aeon/gnode/execute',
        operations: ['request.metadata', 'request.read'],
        ucanCapabilities: ['gnosis/steering.run *'],
        runtimeBindingHash:
          'binding-native-runtime-0123456789abcdef0123456789abcdef',
        issuedAt: now,
        expiresAt: now + 60_000,
      },
      privateKey: signer.privateKey,
      keyId: signer.keyId,
      publicKey: signer.publicKey,
    });

    const firstAuth = await deriveExecutionAuthFromHeaders({
      'x-aeon-auth-verified': '1',
      'x-aeon-actor': 'did:key:alice',
      'x-aeon-runtime-binding-hash':
        'binding-native-runtime-0123456789abcdef0123456789abcdef',
      'x-aeon-reactor-handle-grants': JSON.stringify([requestGrant]),
    });
    const replayedAuth = await deriveExecutionAuthFromHeaders({
      'x-aeon-auth-verified': '1',
      'x-aeon-actor': 'did:key:alice',
      'x-aeon-runtime-binding-hash':
        'binding-native-runtime-0123456789abcdef0123456789abcdef',
      'x-aeon-reactor-handle-grants': JSON.stringify([requestGrant]),
    });

    expect(firstAuth?.reactorHandleGrants?.length ?? 0).toBe(1);
    expect(replayedAuth?.reactorHandleGrants?.length ?? 0).toBe(0);
  });

  it('drops forwarded reactor handle grants owned by a different actor', async () => {
    const signer = await generateNativeExecutionReactorGrantSigner(
      'native-auth-owner-test'
    );
    const now = Date.now();
    const requestGrant = await createReactorHandleGrant({
      claims: {
        handleId: 'request:test-owner',
        kind: 'request',
        ownerDid: 'did:key:bob',
        audience: 'aeon://gnosis/native-execution',
        resource: 'POST /.aeon/gnode/execute',
        operations: ['request.metadata', 'request.read'],
        ucanCapabilities: ['gnosis/steering.run *'],
        runtimeBindingHash:
          'binding-native-runtime-0123456789abcdef0123456789abcdef',
        issuedAt: now,
        expiresAt: now + 60_000,
      },
      privateKey: signer.privateKey,
      keyId: signer.keyId,
      publicKey: signer.publicKey,
    });

    const auth = await deriveExecutionAuthFromHeaders({
      'x-aeon-auth-verified': '1',
      'x-aeon-actor': 'did:key:alice',
      'x-aeon-runtime-binding-hash':
        'binding-native-runtime-0123456789abcdef0123456789abcdef',
      'x-aeon-reactor-handle-grants': JSON.stringify([requestGrant]),
    });

    expect(auth?.principal).toBe('did:key:alice');
    expect(auth?.reactorHandleGrants?.length ?? 0).toBe(0);
  });
});
